import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const WelcomePage = () => {
  const [stage, setStage] = useState('tracing'); // tracing -> highlight -> main

  useEffect(() => {
    // Sequence: Trace (2s) -> Highlight Play (1s) -> Show Main
    const timer1 = setTimeout(() => setStage('highlight'), 2000);
    const timer2 = setTimeout(() => setStage('main'), 3500);
    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  const featuresRow1 = [
    { title: 'Course Curator', desc: 'AI picks the single best video for your concept.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions with explanations.' },
    { title: 'Notes Generator', desc: 'Live summaries and key concepts.' },
    { title: 'Course Curator', desc: 'AI picks the single best video.' },
  ];

  const featuresRow2 = [
    { title: 'Revision Scheduler', desc: 'Smart reminders for better retention.' },
    { title: 'Update Acknowledger', desc: 'Stay updated within 48 hours.' },
    { title: 'Premium Features', desc: 'Unlock full learning power.' },
    { title: 'Revision Scheduler', desc: 'Smart reminders.' },
  ];

  return (
    <div className="min-h-screen bg-white text-[#0B3954] overflow-x-hidden font-serif">

      {/* 1. NEURAL TRACE INTRO */}
      <AnimatePresence>
        {stage !== 'main' && (
          <motion.div
            key="intro-stage"
            className="fixed inset-0 flex flex-col items-center justify-center bg-white z-50"
            exit={{ y: '-100%', opacity: 0 }}
            transition={{ duration: 0.8, ease: [0.76, 0, 0.24, 1] }}
          >
            <div className="relative w-64 h-64">
              <svg viewBox="0 0 100 100" className="w-full h-full">
                {/* BRAIN OUTLINE / NEURAL NETWORK */}
                <motion.path
                  d="M50 20C30 20 15 35 15 55C15 75 30 85 50 85C70 85 85 75 85 55C85 35 70 20 50 20Z"
                  fill="none"
                  stroke="#0B3954"
                  strokeWidth="1.5"
                  initial={{ pathLength: 0, opacity: 0 }}
                  animate={{ pathLength: 1, opacity: 1 }}
                  transition={{ duration: 2, ease: "easeInOut" }}
                />
                {/* INNER NEURAL LINES */}
                <motion.path
                  d="M30 50L45 40M45 40L60 55M60 55L75 45M50 30V70"
                  stroke="#0B3954"
                  strokeWidth="1"
                  strokeLinecap="round"
                  initial={{ pathLength: 0 }}
                  animate={{ pathLength: 1 }}
                  transition={{ duration: 1.5, delay: 0.5 }}
                />

                {/* THE PLAY BUTTON NODE */}
                <motion.polygon
                  points="45,45 45,65 65,55"
                  fill={stage === 'highlight' ? "#0B3954" : "none"}
                  stroke="#0B3954"
                  strokeWidth="1"
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ 
                    scale: stage === 'highlight' ? 1.2 : 1, 
                    opacity: 1,
                    filter: stage === 'highlight' ? 'drop-shadow(0 0 8px rgba(11,57,84,0.5))' : 'none'
                  }}
                  transition={{ duration: 0.5 }}
                />
              </svg>
            </div>
            <motion.p 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 1 }}
              className="mt-4 tracking-[0.4em] text-xs font-bold"
            >
              COURSECRAFT AI
            </motion.p>
          </motion.div>
        )}
      </AnimatePresence>

      {/* 2. MAIN CONTENT */}
      {stage === 'main' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.5 }}>

          {/* HEADER */}
          <header className="fixed top-0 left-0 right-0 h-32 flex items-center justify-between px-10 z-40 bg-white/40 backdrop-blur-2xl">
            <div className="flex items-center"> 
               {/* Replaced logo image with a clean SVG for no-background look */}
               <svg viewBox="0 0 100 100" className="h-16 w-16">
                  <path d="M50 20C30 20 15 35 15 55C15 75 30 85 50 85C70 85 85 75 85 55C85 35 70 20 50 20Z" fill="none" stroke="#0B3954" strokeWidth="4"/>
                  <polygon points="45,40 45,70 70,55" fill="#0B3954" />
               </svg>
               <span className="ml-2 font-bold tracking-tighter text-2xl">CC</span>
            </div>

            <div className="flex items-center space-x-10">
              <button className="text-sm font-bold tracking-[0.3em] hover:opacity-50 transition-opacity">LOG IN</button>
              <button className="px-10 py-4 bg-[#0B3954] text-white rounded-full text-xs font-bold tracking-[0.3em] shadow-lg hover:scale-105 active:scale-95 transition-all">
                SIGN UP
              </button>
            </div>
          </header>

          {/* HERO */}
          <section className="h-screen flex flex-col items-center justify-center text-center px-6">
            <motion.div initial={{ y: 30, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.4 }}>
              <h1 className="text-6xl md:text-[10rem] leading-none text-black">
                Welcome to <br />
                <span className="italic font-light text-[#0B3954]">CourseCraft</span>
              </h1>
              <p className="mt-8 text-lg md:text-xl tracking-[0.6em] uppercase text-gray-400 font-light">
                Skip the scroll. <span className="text-black font-semibold">Learn the goal</span>
              </p>
            </motion.div>
          </section>

          {/* FEATURES */}
          <section className="py-40 bg-[#0B3954] text-white overflow-hidden">
             {/* ... Same scrolling features as before ... */}
             <div className="flex mb-12">
              <motion.div className="flex space-x-10 px-4" animate={{ x: [0, -1200] }} transition={{ duration: 30, repeat: Infinity, ease: "linear" }}>
                {featuresRow1.map((f, i) => (
                  <div key={i} className="min-w-[450px] h-72 p-12 bg-white/5 border border-white/10 rounded-[3rem] flex flex-col justify-end group hover:bg-white/10 transition-all">
                    <h3 className="text-2xl font-bold mb-2">{f.title}</h3>
                    <p className="text-white/60 text-lg leading-relaxed">{f.desc}</p>
                  </div>
                ))}
              </motion.div>
            </div>
          </section>

          <footer className="py-20 flex flex-col items-center justify-center bg-white">
             <p className="text-[10px] tracking-[0.5em] text-gray-400 uppercase">© 2026 CourseCraft AI</p>
          </footer>
        </motion.div>
      )}
    </div>
  );
};

export default WelcomePage;
